function getProductById(id){return PRODUCTS.find(p=>p.id===id);}
function getProductsByCategory(cat){if(cat==='all')return PRODUCTS;return PRODUCTS.filter(p=>p.category===cat);}
function getTrending(){return PRODUCTS.filter(p=>p.badge==='hot').slice(0,8);}
function getNewArrivals(){return PRODUCTS.filter(p=>p.badge==='new').slice(0,8);}
function searchProducts(q){if(!q)return PRODUCTS;const s=q.toLowerCase();return PRODUCTS.filter(p=>p.name.toLowerCase().includes(s)||p.brand.toLowerCase().includes(s)||p.category.toLowerCase().includes(s));}
function formatPrice(p){return '₹'+p.toLocaleString('en-IN');}
function getDiscount(now,was){return Math.round((1-now/was)*100);}
